constexpr int kFullThreadsPerBlock = 256;
constexpr int kHalfThreadsPerBlock = 128;
constexpr int kReduceThreads = 256;
constexpr size_t kStaticChunkSize = 4096;

template <typename T, int BLOCK_THREADS>
__global__ void reduce_sum_kernel(const T* __restrict__ in,
                                  T* __restrict__ out,
                                  size_t n) {
  size_t idx = static_cast<size_t>(blockIdx.x) * (BLOCK_THREADS * 2) +
               static_cast<size_t>(threadIdx.x);

  T sum = 0;
  if (idx < n) sum += in[idx];
  if (idx + BLOCK_THREADS < n) sum += in[idx + BLOCK_THREADS];

  __shared__ T sdata[BLOCK_THREADS];
  sdata[threadIdx.x] = sum;
  __syncthreads();

  for (int stride = BLOCK_THREADS / 2; stride > 0; stride >>= 1) {
    if (threadIdx.x < stride) {
      sdata[threadIdx.x] += sdata[threadIdx.x + stride];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    out[blockIdx.x] = sdata[0];
  }
}

template <typename T>
__global__ void write_back_kernel(T* dst, const T* src) {
  if (blockIdx.x == 0 && threadIdx.x == 0) {
    dst[0] = src[0];
  }
}

#ifdef BASELINE_IMPL

template <typename Element, size_t compute_iterations, int BLOCK_THREADS>
__global__ void bench_kernel(Element* data, size_t len, Element* partial_sums) {
  const size_t it_base = static_cast<size_t>(blockIdx.x) * kStaticChunkSize;
  if (it_base >= len) return;

  const Element f = data[it_base];
  Element local_sum = 0;

  for (size_t i = threadIdx.x; i < kStaticChunkSize && (it_base + i) < len;
       i += BLOCK_THREADS) {
    Element t = data[it_base + i];
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    local_sum += t;
  }

  __shared__ Element sdata[BLOCK_THREADS];
  sdata[threadIdx.x] = local_sum;
  __syncthreads();

  for (int stride = BLOCK_THREADS / 2; stride > 0; stride >>= 1) {
    if (threadIdx.x < stride) {
      sdata[threadIdx.x] += sdata[threadIdx.x + stride];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    partial_sums[blockIdx.x] = sdata[0];
  }
}

#else

template <typename Element, size_t compute_iterations, int BLOCK_THREADS>
__global__ void bench_kernel(Element* data, size_t len, Element* partial_sums) {
  const size_t it_base = static_cast<size_t>(blockIdx.x) * kStaticChunkSize;
  if (it_base >= len) return;

  __shared__ Element f[8];
  if (threadIdx.x < 8) {
    const size_t idx = it_base + static_cast<size_t>(threadIdx.x);
    f[threadIdx.x] = (idx < len) ? data[idx] : Element(0);
  }
  __syncthreads();

  Element local_sum = 0;

  for (size_t i = threadIdx.x; i < kStaticChunkSize && (it_base + i) < len;
       i += BLOCK_THREADS) {
    const Element v = data[it_base + i];
    Element t0 = v, t1 = v, t2 = v, t3 = v;
    Element t4 = v, t5 = v, t6 = v, t7 = v;

    for (size_t j = 0; j < compute_iterations / 8; j++) {
      t0 = t0 * t0 + f[0];
      t1 = t1 * t1 + f[1];
      t2 = t2 * t2 + f[2];
      t3 = t3 * t3 + f[3];
      t4 = t4 * t4 + f[4];
      t5 = t5 * t5 + f[5];
      t6 = t6 * t6 + f[6];
      t7 = t7 * t7 + f[7];
    }

    if (compute_iterations % 8 > 0) t0 = t0 * t0 + f[0];
    if (compute_iterations % 8 > 1) t1 = t1 * t1 + f[1];
    if (compute_iterations % 8 > 2) t2 = t2 * t2 + f[2];
    if (compute_iterations % 8 > 3) t3 = t3 * t3 + f[3];
    if (compute_iterations % 8 > 4) t4 = t4 * t4 + f[4];
    if (compute_iterations % 8 > 5) t5 = t5 * t5 + f[5];
    if (compute_iterations % 8 > 6) t6 = t6 * t6 + f[6];

    local_sum += t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
  }

  __shared__ Element sdata[BLOCK_THREADS];
  sdata[threadIdx.x] = local_sum;
  __syncthreads();

  for (int stride = BLOCK_THREADS / 2; stride > 0; stride >>= 1) {
    if (threadIdx.x < stride) {
      sdata[threadIdx.x] += sdata[threadIdx.x + stride];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    partial_sums[blockIdx.x] = sdata[0];
  }
}

