template <typename Element, size_t compute_iterations, int BLOCK_THREADS>
void bench_launch(size_t len,
                  Element* src,
                  Element* partial1,
                  Element* partial2) {
  const size_t blocks = (len + kStaticChunkSize - 1) / kStaticChunkSize;

  bench_kernel<Element, compute_iterations, BLOCK_THREADS>
      <<<static_cast<unsigned int>(blocks), BLOCK_THREADS>>>(src, len, partial1);

  size_t current = blocks;
  Element* in = partial1;
  Element* out = partial2;

  while (current > 1) {
    const size_t reduce_blocks =
        (current + (kReduceThreads * 2 - 1)) / (kReduceThreads * 2);
    reduce_sum_kernel<Element, kReduceThreads>
        <<<static_cast<unsigned int>(reduce_blocks), kReduceThreads>>>(in, out,
                                                                       current);
    current = reduce_blocks;
    Element* tmp = in;
    in = out;
    out = tmp;
  }

  write_back_kernel<Element><<<1, 1>>>(src, in);
}

template <typename Element, size_t compute_iterations>
size_t bench(size_t len,
             const Element seed1,
             const Element seed2,
             Element* src,
             void* partial1_raw,
             void* partial2_raw,
             int threads_per_block) {
  (void)seed1;
  (void)seed2;

  Element* partial1 = reinterpret_cast<Element*>(partial1_raw);
  Element* partial2 = reinterpret_cast<Element*>(partial2_raw);

  if (threads_per_block <= kHalfThreadsPerBlock) {
    bench_launch<Element, compute_iterations, kHalfThreadsPerBlock>(
        len, src, partial1, partial2);
  } else {
    bench_launch<Element, compute_iterations, kFullThreadsPerBlock>(
        len, src, partial1, partial2);
  }

  CUDA_SAFE_CALL(cudaGetLastError());
  return len;
}

