template <typename Op>
double measure_operation(Op op) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));

  CUDA_SAFE_CALL(cudaEventRecord(start, 0));
  op();
  CUDA_SAFE_CALL(cudaEventRecord(stop, 0));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));

  float elapsed_ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&elapsed_ms, start, stop));
  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));

  return static_cast<double>(elapsed_ms);
}

template <typename Op>
double benchmark_cuda(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  (void)op(kFullThreadsPerBlock);

  std::vector<double> measurements;
  measurements.reserve((total_runs - 1) + (total_half_thread_runs - 1));

  for (int i = 1; i < total_runs; i++) {
    measurements.push_back(op(kFullThreadsPerBlock));
  }

  if (kFullThreadsPerBlock > 1) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      measurements.push_back(op(kHalfThreadsPerBlock));
    }
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

