  const size_t num_elements = ctx.memory_space_bytes / sizeof(double);
  double* ptr = reinterpret_cast<double*>(ctx.d_buffer);
  bench<double, 16>(num_elements, 1.0, -1.0, ptr, ctx.d_partial1,
                    ctx.d_partial2, kFullThreadsPerBlock);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());
}

