constexpr int kThreadsPerBlock = 256;
constexpr size_t kStaticChunkSize = 4096;

template <typename T, unsigned int compute_iterations>
__device__ __forceinline__ T bench_element(const T* data, size_t idx) {
  const size_t chunk_base = (idx / kStaticChunkSize) * kStaticChunkSize;

#ifdef BASELINE_IMPL
  T f = data[chunk_base];
  T t = data[idx];
#pragma unroll
  for (unsigned int j = 0; j < compute_iterations; ++j) {
    t = t * t + f;
  }
  return t;
#else
  const T f0 = data[chunk_base + 0];
  const T f1 = data[chunk_base + 1];
  const T f2 = data[chunk_base + 2];
  const T f3 = data[chunk_base + 3];
  const T f4 = data[chunk_base + 4];
  const T f5 = data[chunk_base + 5];
  const T f6 = data[chunk_base + 6];
  const T f7 = data[chunk_base + 7];

  const T v = data[idx];
  T t0 = v, t1 = v, t2 = v, t3 = v, t4 = v, t5 = v, t6 = v, t7 = v;

#pragma unroll
  for (unsigned int j = 0; j < compute_iterations / 8; ++j) {
    t0 = t0 * t0 + f0;
    t1 = t1 * t1 + f1;
    t2 = t2 * t2 + f2;
    t3 = t3 * t3 + f3;
    t4 = t4 * t4 + f4;
    t5 = t5 * t5 + f5;
    t6 = t6 * t6 + f6;
    t7 = t7 * t7 + f7;
  }

  if (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
  if (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
  if (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
  if (compute_iterations % 8 > 3) t3 = t3 * t3 + f3;
  if (compute_iterations % 8 > 4) t4 = t4 * t4 + f4;
  if (compute_iterations % 8 > 5) t5 = t5 * t5 + f5;
  if (compute_iterations % 8 > 6) t6 = t6 * t6 + f6;

  return t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
#endif
}

template <typename T, unsigned int compute_iterations>
__global__ void bench_kernel(const T* data, size_t len, T* partials) {
  __shared__ T sdata[kThreadsPerBlock];

  T local_sum = 0;
  const size_t stride = static_cast<size_t>(blockDim.x) * gridDim.x;
  for (size_t idx = static_cast<size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
       idx < len; idx += stride) {
    local_sum += bench_element<T, compute_iterations>(data, idx);
  }

  sdata[threadIdx.x] = local_sum;
  __syncthreads();

  for (int offset = blockDim.x / 2; offset > 0; offset >>= 1) {
    if (threadIdx.x < offset) {
      sdata[threadIdx.x] += sdata[threadIdx.x + offset];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    partials[blockIdx.x] = sdata[0];
  }
}

template <typename T>
__global__ void store_first_kernel(T* data, T value) {
  if (blockIdx.x == 0 && threadIdx.x == 0) {
    data[0] = value;
  }
}

int get_sm_count() {
  static int sm_count = [] {
    int device = 0;
    CUDA_SAFE_CALL(cudaGetDevice(&device));
    int sms = 1;
    CUDA_SAFE_CALL(
        cudaDeviceGetAttribute(&sms, cudaDevAttrMultiProcessorCount, device));
    return sms > 0 ? sms : 1;
  }();
  return sm_count;
}

int choose_blocks(size_t len) {
  const size_t needed = (len + kThreadsPerBlock - 1) / kThreadsPerBlock;
  const size_t preferred = static_cast<size_t>(get_sm_count()) * 32;
  const size_t blocks = std::max<size_t>(1, std::min(needed, preferred));
  return static_cast<int>(blocks);
}

template <typename T, unsigned int compute_iterations>
size_t bench(size_t len,
             const T /*seed1*/,
             const T /*seed2*/,
             T* d_src,
             int blocks,
             T* d_partials,
             std::vector<T>& h_partials) {
  bench_kernel<T, compute_iterations>
      <<<blocks, kThreadsPerBlock>>>(d_src, len, d_partials);
  CUDA_SAFE_CALL(cudaGetLastError());

  CUDA_SAFE_CALL(cudaMemcpy(h_partials.data(), d_partials, blocks * sizeof(T),
                            cudaMemcpyDeviceToHost));

  T sum = 0;
  for (int i = 0; i < blocks; ++i) {
    sum += h_partials[i];
  }

  store_first_kernel<T><<<1, 1>>>(d_src, sum);
  CUDA_SAFE_CALL(cudaGetLastError());
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  return len;
}

auto runbench_warmup(void* d_buffer, void* d_partials, size_t size_bytes) {
  const size_t num_elements = size_bytes / sizeof(double);
  const int blocks = choose_blocks(num_elements);
  std::vector<double> h_partials(blocks);

  auto timer_start = benchmark_clock::now();
  bench<double, 16>(num_elements, 1.0, -1.0, static_cast<double*>(d_buffer),
                    blocks, static_cast<double*>(d_partials), h_partials);
  auto timer_duration = benchmark_clock::now() - timer_start;

  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration)
      .count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration)
             .count() /
         1000.0;
}

template <typename Op1, typename Op2>
auto benchmark_cuda(Op1 op_full, Op2 op_half) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op_full();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op_full();
    measurements.push_back(duration);
  }

  for (int i = 1; i < total_half_thread_runs; i++) {
    duration = op_half();
    measurements.push_back(duration);
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <typename T, unsigned int compute_iterations>
double benchmark_type(void* d_buffer, void* d_partials, size_t size_bytes) {
  const size_t len = size_bytes / sizeof(T);
  const int blocks_full = choose_blocks(len);
  const int blocks_half = std::max(1, blocks_full / 2);

  std::vector<T> h_partials_full(blocks_full);
  std::vector<T> h_partials_half(blocks_half);

  T* d_src = static_cast<T*>(d_buffer);

  auto full_op = [&] {
    return measure_operation([&] {
      bench<T, compute_iterations>(len, static_cast<T>(1), static_cast<T>(-1),
                                   d_src, blocks_full,
                                   static_cast<T*>(d_partials),
                                   h_partials_full);
    });
  };

  auto half_op = [&] {
    return measure_operation([&] {
      bench<T, compute_iterations>(len, static_cast<T>(1), static_cast<T>(-1),
                                   d_src, blocks_half,
                                   static_cast<T*>(d_partials),
                                   h_partials_half);
    });
  };

  return benchmark_cuda(full_op, half_op);
}

template <unsigned int compute_iterations>
void runbench(void* d_buffer, void* d_partials, size_t size_bytes) {
  ComputeSpace cs{size_bytes, static_cast<int>(compute_iterations)};

  auto kernel_time_mad_sp =
